solutions.javascript:
// Solution
function validatePortMappings(composeFile) {
  try {
    const compose = JSON.parse(composeFile);
    const ports = compose.services.web.ports;
    const hostPorts = new Set();
    for (const port of ports) {
      const [containerPort, hostPort] = port.split(':');
      if (isNaN(containerPort) || isNaN(hostPort)) {
        return false;
      }
      if (hostPorts.has(hostPort)) {
        return false;
      }
      hostPorts.add(hostPort);
    }
    return true;
  } catch (e) {
    return false;
  }
}

solutions.python:
class Solution:
  def validate_port_mappings(self, compose_file: str) -> bool:
    try:
      compose = JSON.parse(compose_file)
      ports = compose['services']['web']['ports']
      host_ports = set()
      for port in ports:
        container_port, host_port = port.split(':')
        if not container_port.isnumeric() or not host_port.isnumeric():
          return False
        if host_port in host_ports:
          return False
        host_ports.add(host_port)
      return True
    except Exception as e:
      return False
